import React from 'react';
import { Link } from 'gatsby';

const Header = ({ siteTitle, pageTitle }) => {
  const handleHomeClick = (e) => {
    e.preventDefault(); // Prevent the default link behavior

    // Clear local storage items related to category and load more count
    if (typeof window !== 'undefined') {
      localStorage.removeItem('selectedCategory');
      localStorage.removeItem('loadMoreCount');
      window.location.replace("/");
    }
  };

  return (
    <header>
      <div className="container">
        <h1>
          <Link to="/" onClick={handleHomeClick}>SP</Link>
        </h1>
        <nav className="menu">
          <ul>
            <li><Link to="/about" activeClassName="underline">About Shaun</Link></li>
            <li><Link to="/chat-with-shaun" activeClassName="underline">Chat With Shaun</Link></li>
          </ul>
        </nav>
      </div>
    </header>
  );
};

export default Header;
